// ═══════════════════════════════════════
// AGENTE DIAGNÓSTICO — Clasificación de Patrones
// ═══════════════════════════════════════
const input = $('Webhook Diagnóstico').first().json.body || $('Webhook Diagnóstico').first().json;
const area = input.area || 'unknown';
const kwh = Number(input.kwh) || 0;
const ema = Number(input.ema) || 0;
const severity = input.severity || 'Normal';

// Datos históricos
const hist = $('Historial 24h').first().json;
const hourly = $('Tendencia Horaria').all().map(i => i.json);
const anomalies = $('Anomalías Recientes').all().map(i => i.json);

const totalReadings = Number(hist.total_readings) || 0;
const avgKwh = Number(hist.avg_kwh) || 0;
const maxKwh = Number(hist.max_kwh) || 0;
const minKwh = Number(hist.min_kwh) || 0;
const stddev = Number(hist.stddev_kwh) || 0;
const anomalyCount = Number(hist.anomaly_count) || 0;

// ── Clasificar tipo de patrón ──
let patternType = 'normal';
let patternDesc = '';

// Consumo anormalmente bajo
if (avgKwh > 0 && kwh < avgKwh * 0.2) {
  patternType = 'abnormally_low';
  patternDesc = `Consumo anormalmente bajo (${kwh.toFixed(2)} kWh vs promedio ${avgKwh.toFixed(2)}). Posible apagado inesperado.`;
}
// Patrón sostenido: muchas anomalías en 24h
else if (anomalyCount > 5) {
  patternType = 'sustained';
  patternDesc = `Patrón sostenido: ${anomalyCount} anomalías en 24h. No es evento puntual, requiere intervención.`;
}
// Acelerado: alta desviación con tendencia alcista
else if (stddev > 0 && avgKwh > 0 && (kwh - avgKwh) / avgKwh > 0.3) {
  patternType = 'accelerating';
  patternDesc = `Tendencia acelerada: lectura ${kwh.toFixed(2)} supera promedio ${avgKwh.toFixed(2)} por >30%. STD: ${stddev.toFixed(2)}.`;
}
// Puntual: evento aislado
else if (anomalyCount <= 2) {
  patternType = 'punctual';
  patternDesc = `Evento puntual: solo ${anomalyCount} anomalías en 24h. Probablemente transitorio.`;
}
else {
  patternType = 'moderate';
  patternDesc = `Patrón intermedio: ${anomalyCount} anomalías con variabilidad moderada.`;
}

// ── Contexto enriquecido para LLM ──
const isRecurring = anomalies.length >= 3;
let promptAddon = `CONTEXTO HISTÓRICO: ${patternDesc}`;
if (isRecurring) {
  promptAddon += ` | ⚠️ ALERTA RECURRENTE: Evento #${anomalies.length} en esta área.`;
}
if (patternType === 'abnormally_low') {
  promptAddon += ' | NOTA: Consumo inusualmente BAJO. Verificar si equipos fueron desconectados.';
}

// Tendencia horaria resumida
const hourlyTrend = hourly.map(h => `${h.hora}: ${h.avg_kwh} kWh`).join(', ');

return [{ json: {
  action: 'diagnosis_complete',
  area,
  severity,
  pattern_type: patternType,
  pattern_description: patternDesc,
  history: {
    readings_24h: totalReadings,
    avg_kwh: avgKwh,
    max_kwh: maxKwh,
    min_kwh: minKwh,
    stddev: stddev,
    anomaly_count: anomalyCount
  },
  recent_anomalies_count: anomalies.length,
  is_recurring: isRecurring,
  should_escalate: ['sustained', 'accelerating'].includes(patternType),
  enriched_prompt: promptAddon,
  hourly_trend: hourlyTrend,
  timestamp: new Date().toISOString()
} }];

// Respuesta final del agente diagnóstico
const data = $('Clasificar Patrón').first().json;
return [{ json: data }];
